class _LazyCursorMap(Mapping[str, type[Cursor]]):
    """Position → cursor class; imports the domain module on first use."""

    __slots__ = ()

    def __getitem__(self, key: str) -> type[Cursor]:
        module, name = _INDEX[key]
        loaded = import_module(f"{__name__}.{module}")
        return cast("type[Cursor]", getattr(loaded, name))

    def __iter__(self) -> Iterator[str]:
        return iter(_INDEX)

    def __len__(self) -> int:
        return len(_INDEX)


CURSOR_FOR: Mapping[str, type[Cursor]] = _LazyCursorMap()


def __getattr__(name: str) -> Any:
    """Expose cursor classes lazily (``from …_generated_cursors import BdCursor``)."""
    if module := _EXPORTS.get(name):
        return getattr(import_module(f"{__name__}.{module}"), name)
    raise AttributeError(f"module {__name__!r} has no attribute {name!r}")


def design() -> UniCursor:
    """Create an empty detached design rooted at ``polUni`` (``uni``).

    The uniform entry point for multi-domain designs: every other root
    factory (``tenant()``, ``infra()``, ``fabric()``, ``controller()``)
    is sugar for ``design().<maker>(...)``.  No session and no I/O —
    the tree is built in memory and pushed later via ``push()``.

    Returns:
        Root :class:`UniCursor` of a new empty design.

    Example::

        cfg = design()
        cfg.fabric().datetime_policy("prod-ntp")
        cfg.infra().vlan_pool("prod", "static")
        cfg.tenant("prod").vrf("main")
        payload = cfg.to_payload()   # one atomic polUni envelope
    """
    from niwaki.design._generated_cursors._uni import UniCursor
    from niwaki.models._generated.pol.polUni import polUni

    return UniCursor(DesignNode(polUni, "uni", {}, {}, None, position=""))


def tenant(
    name: str,
    *,
    annotation: str | None = None,
    description: str | None = None,
    display_name: str | None = None,
    owner_key: str | None = None,
    owner_tag: str | None = None,
    userdom: str | None = None,
) -> TenantCursor:
    """Create a detached design and declare its ``fvTenant`` root.

    Shorthand for ``design().tenant(...)`` — the returned cursor
    sits on the declared object; the design root is the enclosing
    ``polUni`` node, so sibling domains stay reachable through the
    implicit-pop makers.

    Returns:
        :class:`TenantCursor` on the new ``fvTenant`` node.
    """
    params = {k: v for k, v in locals().items() if k not in ("name",)}
    return design().tenant(name, **_prune(params))


